"use client"

/**
 * 収支推移・原価内訳のチャート群。LineChart / LabeledDonutCard は formatValue（関数 prop）を
 * 取るため "use client" 境界に置く（サーバーから関数 prop を渡すと next build が壊れる）。
 */

import * as React from "react"
import {
  LineChart,
  LabeledDonutCard,
  ChartLegend,
  formatCurrency,
  formatPercent,
} from "@gunjo/ui"
import {
  MONTHLY,
  PROFIT_BUDGET,
  COST_BREAKDOWN,
  TOTAL_COST,
  type MonthlyPnl,
  type CostItem,
} from "./data"

const yen = (v: number) => formatCurrency(v, { compact: true, maximumFractionDigits: 1 })
const yenFull = (v: number) => formatCurrency(v)

/* ───────────────────────── 収支の推移 ───────────────────────── */

export function RevenueProfitTrend({ months = MONTHLY }: { months?: MonthlyPnl[] }) {
  const series = React.useMemo(
    () => [
      {
        label: "運送収入",
        color: "primary" as const,
        data: months.map((m) => ({ label: m.month, value: m.revenue })),
      },
      {
        label: "営業利益",
        color: "success" as const,
        data: months.map((m) => ({ label: m.month, value: m.operatingProfit })),
      },
    ],
    [months],
  )

  return (
    <LineChart
      series={series}
      variant="line"
      showGrid
      showDots
      showLabels
      showLegend
      referenceValue={PROFIT_BUDGET}
      referenceLabel={`営業利益 目標 ${yen(PROFIT_BUDGET)}`}
      formatValue={yen}
      aria-label="運送収入と営業利益の月次推移（会計年度・4月始まり）。破線は営業利益の月次目標。"
    />
  )
}

/* ───────────────────── 運送原価の内訳（ドーナツ） ───────────────────── */

export function CostBreakdownDonut({
  items = COST_BREAKDOWN,
  total = TOTAL_COST,
}: {
  items?: CostItem[]
  total?: number
}) {
  const segments = items.map((c) => ({
    label: c.label,
    value: c.amount,
    color: c.tone,
  }))

  return (
    <LabeledDonutCard
      title="運送原価の内訳"
      description="2026年5月度・運送原価 167.9百万円"
      segments={segments}
      centerLabel="運送原価"
      centerValue={yen(total)}
      showCallouts={false}
      formatValue={yenFull}
      totalLabel="運送原価 合計"
    />
  )
}

/**
 * ドーナツの凡例だけを別カラムに出したいとき用（金額 + 構成比）。
 * NOTE: ChartLegend は formatValue を持たず、value は事前整形済みの ReactNode を要求するので
 * 表示はこちらで組み立てる（DonutChart/LineChart の formatValue とは API が非対称）。
 */
export function CostBreakdownLegend({
  items = COST_BREAKDOWN,
  total = TOTAL_COST,
}: {
  items?: CostItem[]
  total?: number
}) {
  return (
    <ChartLegend
      variant="vertical"
      items={items.map((c) => ({
        label: c.label,
        value: `${yen(c.amount)}・${formatPercent(c.amount / total, { maximumFractionDigits: 1 })}`,
        color: c.tone,
      }))}
    />
  )
}

/**
 * 月星ロジスティクス株式会社 — 関東中央営業所
 * 運送原価・収支管理ダッシュボード用データ（2026年5月度 / 当期累計）
 *
 * RSC-safe: 純データと純ヘルパーのみ。"use client" を付けない（page.tsx がサーバーで集計に使う）。
 * 関数 prop を取る @gunjo/ui コンポーネントは Charts.tsx / PnlTable.tsx 側（"use client"）で描画する。
 */

export const OFFICE = {
  company: "月星ロジスティクス株式会社",
  office: "関東中央営業所",
  period: "2026年5月度",
  fiscal: "2026年3月期 第2四半期",
} as const

/* ───────────────────────── 全社/営業所 KPI ───────────────────────── */

/** KPI の良し悪しの向き。high = 高いほど良い（利益率・実車率）、low = 低いほど良い（原価率・人件費率）。 */
export type GoodWhen = "high" | "low"

export interface KpiMetric {
  key: string
  label: string
  /** 当月の実数値（率は 0–1 の比率）。 */
  value: number
  kind: "currency" | "percent" | "ratio"
  /** 前年同月比の変化量（率はポイント差 = 当月比率 − 前年比率、金額は円差）。 */
  changeVsPrevYear: number
  /** この指標は「高いほど良い」か「低いほど良い」か。up/down の色判定に使う。 */
  goodWhen: GoodWhen
  /** 予算（目標）。任意。 */
  budget?: number
}

export const KPIS: KpiMetric[] = [
  {
    key: "revenue",
    label: "運送収入",
    value: 184_320_000,
    kind: "currency",
    changeVsPrevYear: 6_410_000, // 前年比 +6.4M（増収）
    goodWhen: "high",
    budget: 190_000_000,
  },
  {
    key: "operatingProfit",
    label: "営業利益",
    value: 7_930_000,
    kind: "currency",
    changeVsPrevYear: -2_180_000, // 前年比 −2.18M（減益）
    goodWhen: "high",
    budget: 11_400_000,
  },
  {
    key: "operatingMargin",
    label: "営業利益率",
    value: 0.043,
    kind: "ratio",
    changeVsPrevYear: -0.014, // 前年比 −1.4pt
    goodWhen: "high",
    budget: 0.06,
  },
  {
    key: "costRatio",
    label: "原価率",
    value: 0.911,
    kind: "ratio",
    changeVsPrevYear: 0.012, // 前年比 +1.2pt ＝ 悪化（low が良い）
    goodWhen: "low",
    budget: 0.9,
  },
  {
    key: "loadedRatio",
    label: "実車率",
    value: 0.781,
    kind: "ratio",
    changeVsPrevYear: -0.023, // 前年比 −2.3pt ＝ 悪化（high が良い）
    goodWhen: "high",
    budget: 0.82,
  },
]

/* ───────────────────── 収支の推移（月次トレンド） ───────────────────── */

export interface MonthlyPnl {
  month: string // 会計年度（4月始まり）
  revenue: number // 運送収入
  cost: number // 運送原価
  operatingProfit: number // 営業利益
}

export const MONTHLY: MonthlyPnl[] = [
  { month: "4月", revenue: 178_900_000, cost: 162_100_000, operatingProfit: 9_640_000 },
  { month: "5月", revenue: 184_320_000, cost: 167_900_000, operatingProfit: 7_930_000 },
  { month: "6月", revenue: 181_400_000, cost: 165_800_000, operatingProfit: 8_010_000 },
  { month: "7月", revenue: 192_700_000, cost: 173_200_000, operatingProfit: 11_120_000 },
  { month: "8月", revenue: 169_500_000, cost: 158_900_000, operatingProfit: 4_280_000 },
  { month: "9月", revenue: 187_300_000, cost: 169_400_000, operatingProfit: 9_510_000 },
]

/** 月次予算（営業利益の目標線）。 */
export const PROFIT_BUDGET = 9_500_000

/* ───────────────────── 運送原価の内訳（当月） ───────────────────── */

export interface CostItem {
  label: string
  amount: number
  /** チャートの色トーン（@gunjo/ui の ChartTone）。 */
  tone: "primary" | "warning" | "info" | "accent" | "destructive" | "muted" | "success"
}

/** 運送原価 167,900,000 の内訳。人件費（運転者）と燃料費でほぼ7割。 */
export const COST_BREAKDOWN: CostItem[] = [
  { label: "人件費（運転者）", amount: 78_300_000, tone: "primary" },
  { label: "燃料費（軽油）", amount: 34_600_000, tone: "warning" },
  { label: "外注費（傭車）", amount: 21_900_000, tone: "info" },
  { label: "車両費（減価償却・修繕）", amount: 16_400_000, tone: "accent" },
  { label: "高速代", amount: 9_800_000, tone: "destructive" },
  { label: "保険料・その他", amount: 6_900_000, tone: "muted" },
]

export const TOTAL_COST = COST_BREAKDOWN.reduce((s, c) => s + c.amount, 0)

/* ───────────────── 車両別 / 荷主別 収支（中核テーブル） ───────────────── */

export interface VehiclePnl {
  vehicle: string // 号車
  type: string // 車種
  driver: string // 主乗務員
  revenue: number // 運送収入
  cost: number // 運送原価
  loadedRatio: number // 実車率 0–1
  /** 走行キロ（実車キロは loadedRatio から導出可）。 */
  runKm: number
}

/** 22台の保有車両のうち主要12台。営業利益・利益率は導出。 */
export const VEHICLES: VehiclePnl[] = [
  { vehicle: "関central 1101", type: "大型ウィング", driver: "佐藤 健", revenue: 11_240_000, cost: 9_180_000, loadedRatio: 0.91, runKm: 18_400 },
  { vehicle: "関central 1102", type: "大型平", driver: "鈴木 一郎", revenue: 9_870_000, cost: 8_240_000, loadedRatio: 0.88, runKm: 17_900 },
  { vehicle: "関central 1108", type: "大型冷凍", driver: "田中 浩二", revenue: 12_910_000, cost: 11_030_000, loadedRatio: 0.84, runKm: 19_600 },
  { vehicle: "関central 2203", type: "増トン", driver: "山本 大輔", revenue: 7_640_000, cost: 7_120_000, loadedRatio: 0.76, runKm: 15_200 },
  { vehicle: "関central 2208", type: "増トン", driver: "中村 翔", revenue: 6_980_000, cost: 7_410_000, loadedRatio: 0.62, runKm: 14_800 },
  { vehicle: "関central 3304", type: "4t", driver: "小林 誠", revenue: 5_410_000, cost: 4_980_000, loadedRatio: 0.79, runKm: 12_100 },
  { vehicle: "関central 3309", type: "4t", driver: "加藤 亮", revenue: 4_120_000, cost: 4_690_000, loadedRatio: 0.58, runKm: 11_300 },
  { vehicle: "関central 4401", type: "大型ウィング", driver: "吉田 修", revenue: 10_330_000, cost: 8_870_000, loadedRatio: 0.86, runKm: 18_100 },
  { vehicle: "関central 4407", type: "大型平", driver: "斎藤 学", revenue: 8_240_000, cost: 8_010_000, loadedRatio: 0.71, runKm: 16_400 },
  { vehicle: "関central 5502", type: "トレーラー", driver: "渡辺 隆", revenue: 13_780_000, cost: 11_240_000, loadedRatio: 0.89, runKm: 20_300 },
  { vehicle: "関central 5506", type: "トレーラー", driver: "伊藤 剛", revenue: 9_410_000, cost: 9_980_000, loadedRatio: 0.64, runKm: 18_700 },
  { vehicle: "関central 6601", type: "4t冷凍", driver: "松本 健太", revenue: 6_120_000, cost: 5_440_000, loadedRatio: 0.82, runKm: 13_500 },
]

export interface CustomerPnl {
  customer: string // 荷主
  lane: string // 主要方面
  revenue: number
  cost: number
  /** 当社の実勢運賃（円/車・標準ロット）。 */
  actualRate: number
  /** 標準的運賃（2024告示）に基づく目安運賃（円/車・同条件）。 */
  standardRate: number
}

/** 主要荷主8社。標準的運賃との乖離を actualRate / standardRate で比較。 */
export const CUSTOMERS: CustomerPnl[] = [
  { customer: "東関東食品㈱", lane: "東京→仙台", revenue: 24_800_000, cost: 20_900_000, actualRate: 88_000, standardRate: 92_000 },
  { customer: "セントラル流通㈱", lane: "東京→大阪", revenue: 31_200_000, cost: 28_640_000, actualRate: 121_000, standardRate: 134_000 },
  { customer: "北日本建材㈱", lane: "宇都宮→新潟", revenue: 14_600_000, cost: 13_980_000, actualRate: 61_000, standardRate: 68_000 },
  { customer: "みなと物産㈱", lane: "横浜→名古屋", revenue: 18_900_000, cost: 15_100_000, actualRate: 76_000, standardRate: 74_000 },
  { customer: "ヤマト精機㈱", lane: "東京→静岡", revenue: 9_400_000, cost: 9_980_000, actualRate: 42_000, standardRate: 51_000 },
  { customer: "関東ロジ商事㈱", lane: "東京→金沢", revenue: 12_300_000, cost: 10_400_000, actualRate: 83_000, standardRate: 86_000 },
  { customer: "城南運輸倉庫㈱", lane: "川崎→水戸", revenue: 7_800_000, cost: 8_410_000, actualRate: 34_000, standardRate: 44_000 },
  { customer: "日東デイリー㈱", lane: "東京→盛岡", revenue: 16_400_000, cost: 13_700_000, actualRate: 97_000, standardRate: 99_000 },
]

/* ───────────────────────── 導出ヘルパー（純関数） ───────────────────────── */

export interface VehicleRow extends VehiclePnl {
  profit: number
  margin: number
}

export function withVehicleProfit(v: VehiclePnl): VehicleRow {
  const profit = v.revenue - v.cost
  return { ...v, profit, margin: v.revenue === 0 ? 0 : profit / v.revenue }
}

export interface CustomerRow extends CustomerPnl {
  profit: number
  margin: number
  /** 実勢運賃 − 標準的運賃（負 = 標準割れ）。 */
  rateGap: number
}

export function withCustomerProfit(c: CustomerPnl): CustomerRow {
  const profit = c.revenue - c.cost
  return {
    ...c,
    profit,
    margin: c.revenue === 0 ? 0 : profit / c.revenue,
    rateGap: c.actualRate - c.standardRate,
  }
}

export const VEHICLE_ROWS: VehicleRow[] = VEHICLES.map(withVehicleProfit)
export const CUSTOMER_ROWS: CustomerRow[] = CUSTOMERS.map(withCustomerProfit)

"use client"

/**
 * 車両別 / 荷主別 収支テーブル（中核）。DataTable は ColumnDef の cell に render 関数を取り、
 * formatValue 系も関数 prop なので "use client" 境界に置く。
 *
 * 黒字/赤字の「ひと目」可読性:
 *  - getRowState で赤字行に data-state="loss" を立て、globals なしでも効くよう
 *    インラインの <style> で行を淡赤に着色（DataTable 自体は selected 以外を着色しない）。
 *  - 営業利益セルは Delta（sign 駆動の色＋矢印＋sr-only ラベル）。
 *  - 黒字/赤字は Badge（アイコン＋テキスト＝色だけに依存しない）。
 */

import * as React from "react"
import type { ColumnDef } from "@tanstack/react-table"
import {
  DataTable,
  Delta,
  Badge,
  SegmentedControl,
  formatCurrency,
  formatPercent,
} from "@gunjo/ui"
import {
  VEHICLE_ROWS,
  CUSTOMER_ROWS,
  type VehicleRow,
  type CustomerRow,
} from "./data"

const yen = (v: number) => formatCurrency(v, { compact: true, maximumFractionDigits: 2 })
const pct = (v: number) => formatPercent(v, { maximumFractionDigits: 1 })

/** 営業利益セル: Delta で sign→色（黒字=success / 赤字=destructive）、矢印は隠して金額のみ。 */
function ProfitCell({ value }: { value: number }) {
  return (
    <Delta
      value={value}
      format={(v) => yen(v)}
      labels={{ positive: "黒字", negative: "赤字", zero: "収支均衡" }}
      hideArrow
    />
  )
}

/** 黒字/赤字 ステータスピル（色＋アイコン＋テキスト）。 */
function PnlBadge({ profit }: { profit: number }) {
  return profit >= 0 ? (
    <Badge variant="success">黒字</Badge>
  ) : (
    <Badge variant="destructive">赤字</Badge>
  )
}

/* ───────────────────────── 車両別 列定義 ───────────────────────── */

const vehicleColumns: ColumnDef<VehicleRow>[] = [
  {
    accessorKey: "vehicle",
    header: "号車",
    cell: ({ row }) => (
      <div className="min-w-0">
        <div className="font-medium tabular-nums">{row.original.vehicle}</div>
        <div className="text-xs text-muted-foreground">
          {row.original.type}・{row.original.driver}
        </div>
      </div>
    ),
  },
  {
    accessorKey: "revenue",
    header: "運送収入",
    cell: ({ getValue }) => <span className="tabular-nums">{yen(getValue<number>())}</span>,
  },
  {
    accessorKey: "cost",
    header: "運送原価",
    cell: ({ getValue }) => (
      <span className="tabular-nums text-muted-foreground">{yen(getValue<number>())}</span>
    ),
  },
  {
    accessorKey: "profit",
    header: "営業利益",
    cell: ({ getValue }) => <ProfitCell value={getValue<number>()} />,
  },
  {
    accessorKey: "margin",
    header: "利益率",
    cell: ({ getValue }) => {
      const m = getValue<number>()
      return (
        <span className={m < 0 ? "tabular-nums text-destructive font-medium" : "tabular-nums"}>
          {pct(m)}
        </span>
      )
    },
  },
  {
    accessorKey: "loadedRatio",
    header: "実車率",
    cell: ({ getValue }) => {
      const r = getValue<number>()
      // 実車率は high が良い。低水準(<0.70)は警告色で。
      return (
        <span className={r < 0.7 ? "tabular-nums text-warning font-medium" : "tabular-nums"}>
          {pct(r)}
        </span>
      )
    },
  },
  {
    id: "status",
    header: "収支",
    enableSorting: false,
    cell: ({ row }) => <PnlBadge profit={row.original.profit} />,
  },
]

/* ───────────────────────── 荷主別 列定義 ───────────────────────── */

const customerColumns: ColumnDef<CustomerRow>[] = [
  {
    accessorKey: "customer",
    header: "荷主",
    cell: ({ row }) => (
      <div className="min-w-0">
        <div className="font-medium">{row.original.customer}</div>
        <div className="text-xs text-muted-foreground">{row.original.lane}</div>
      </div>
    ),
  },
  {
    accessorKey: "revenue",
    header: "運送収入",
    cell: ({ getValue }) => <span className="tabular-nums">{yen(getValue<number>())}</span>,
  },
  {
    accessorKey: "profit",
    header: "営業利益",
    cell: ({ getValue }) => <ProfitCell value={getValue<number>()} />,
  },
  {
    accessorKey: "margin",
    header: "利益率",
    cell: ({ getValue }) => {
      const m = getValue<number>()
      return (
        <span className={m < 0 ? "tabular-nums text-destructive font-medium" : "tabular-nums"}>
          {pct(m)}
        </span>
      )
    },
  },
  {
    accessorKey: "rateGap",
    header: "標準運賃差",
    cell: ({ row }) => {
      // 実勢 − 標準的運賃（2024）。負 = 標準割れ（収益性リスク）。
      const gap = row.original.rateGap
      return (
        <div className="flex flex-col">
          <Delta
            value={gap}
            format={(v) => formatCurrency(v, { signed: true })}
            tones={{ positive: "success", negative: "warning", zero: "muted" }}
            labels={{ positive: "標準超", negative: "標準割れ", zero: "標準同等" }}
            showLabel
          />
          <span className="text-xs text-muted-foreground tabular-nums">
            実勢 {formatCurrency(row.original.actualRate)} / 標準 {formatCurrency(row.original.standardRate)}
          </span>
        </div>
      )
    },
  },
  {
    id: "status",
    header: "収支",
    enableSorting: false,
    cell: ({ row }) => <PnlBadge profit={row.original.profit} />,
  },
]

/* ───────────────────────── 公開コンポーネント ───────────────────────── */

const LOSS_ROW_STYLE = `
[data-pnl-table] tr[data-state="loss"] { background-color: hsl(var(--destructive-subtle)); }
[data-pnl-table] tr[data-state="loss"]:hover { background-color: hsl(var(--destructive-subtle)); }
`

export function PnlTable() {
  const [view, setView] = React.useState<"vehicle" | "customer">("vehicle")

  return (
    <div data-pnl-table className="space-y-4">
      {/* DataTable は selected 以外の data-state を着色しないため、赤字行の着色を自前で注入。 */}
      <style>{LOSS_ROW_STYLE}</style>

      <SegmentedControl
        aria-label="収支テーブルの集計軸"
        value={view}
        onValueChange={(v) => setView(v as "vehicle" | "customer")}
        options={[
          { value: "vehicle", label: "車両別" },
          { value: "customer", label: "荷主別" },
        ]}
      />

      {view === "vehicle" ? (
        <DataTable
          columns={vehicleColumns}
          data={VEHICLE_ROWS}
          pageSize={12}
          pageSizeOptions={[12, 25, 50]}
          filter={{ columnId: "vehicle", placeholder: "号車・車種で絞り込み" }}
          getRowState={(row) => (row.profit < 0 ? "loss" : undefined)}
          labels={{
            filterPlaceholder: "号車・車種で絞り込み",
            noResults: "該当する車両がありません",
            rowsPerPage: "表示件数",
          }}
        />
      ) : (
        <DataTable
          columns={customerColumns}
          data={CUSTOMER_ROWS}
          pageSize={12}
          pageSizeOptions={[12, 25, 50]}
          filter={{ columnId: "customer", placeholder: "荷主名で絞り込み" }}
          getRowState={(row) => (row.profit < 0 ? "loss" : undefined)}
          labels={{
            filterPlaceholder: "荷主名で絞り込み",
            noResults: "該当する荷主がありません",
            rowsPerPage: "表示件数",
          }}
        />
      )}
    </div>
  )
}

"use client"

/**
 * 標準的運賃（2024告示）との比較。LimitMonitor は formatValue（関数 prop）を取るため
 * "use client" 境界に置く（サーバーから関数 prop を渡すと next build が壊れる）。
 *
 * 「実勢運賃が標準的運賃を下回らないか」を direction="floor" で監視する:
 *  - 標準以上 = ok、標準間際 = near、標準割れ = over、大幅割れ = critical。
 */

import { LimitMonitor, formatCurrency } from "@gunjo/ui"
import { CUSTOMER_ROWS, type CustomerRow } from "./data"

const yen = (v: number) => formatCurrency(v)

export function StandardRateCompare({ rows = CUSTOMER_ROWS }: { rows?: CustomerRow[] }) {
  return (
    <div className="space-y-3">
      {rows.map((c) => (
        <LimitMonitor
          key={c.customer}
          label={`${c.customer}（${c.lane}）`}
          value={c.actualRate}
          limit={c.standardRate}
          direction="floor"
          warnWithin={5000}
          formatValue={yen}
          labels={{
            ok: "標準以上",
            near: "標準間際",
            over: "標準割れ",
            critical: "大幅割れ",
          }}
        />
      ))}
    </div>
  )
}
